char *minimal8_disassemble_instruction(uint16_t pc, uint32_t raw) {
    static char buf[160];
    char rendered[160];
    (void)rendered;
    uint8_t prefix = 0;
    uint32_t decode_raw = raw;
    uint8_t b0 = (uint8_t)(raw & 0xFF);

    DecodedInstruction inst = minimal8_decode(decode_raw, prefix, pc);
    const char *mnemonic = "UNKNOWN";
    if (inst.valid) {
        switch (inst.category) {
            case CAT_CONTROL:
                if ((inst.prefix == 0x00 && (inst.opcode == 0x00))) {
                    mnemonic = "NOP";
                    break;
                }
                if ((inst.prefix == 0x00 && (inst.opcode == 0xFF))) {
                    mnemonic = "HALT";
                    break;
                }
                break;
            case CAT_ARITHMETIC:
                if ((inst.prefix == 0x00 && ((inst.raw & 0x00F0) == 0x0010))) {
                    mnemonic = "INC";
                    break;
                }
                break;
            default:
                break;
        }
    }

    (void)snprintf(buf, sizeof(buf), "%s OP=%02X PREF=%02X LEN=%u CYC=%u r=%u imm=%u addr=0x%04X disp=%d cc=%u",
                   mnemonic,
                   inst.opcode,
                   inst.prefix,
                   (unsigned int)inst.length,
                   (unsigned int)inst.cycles,
                   (unsigned int)inst.r,
                   (unsigned int)inst.imm,
                   (unsigned int)inst.addr,
                   (int)inst.disp,
                   (unsigned int)inst.cc);
    return buf;
}

void minimal8_trace_instruction(CPUState *cpu, DecodedInstruction *inst) {
    (void)cpu;
    if (!inst) return;
    uint32_t raw_for_disasm = inst->raw;
    if (inst->prefix != 0) {
        raw_for_disasm = ((uint32_t)inst->prefix) | (inst->raw << 8);
    }
    printf("[TRACE] %s\n", minimal8_disassemble_instruction(inst->pc, raw_for_disasm));
}

